import{_ as o,o as t,c as i,ag as a}from"./chunks/framework.DGzMGr_a.js";const m=JSON.parse('{"title":"Cookie 属性详解：HttpOnly、Secure、SameSite 等","description":"","frontmatter":{"title":"Cookie 属性详解：HttpOnly、Secure、SameSite 等","difficulty":"medium","tags":["Cookie","SameSite","HttpOnly","CSRF"],"estimate":15},"headers":[],"relativePath":"domains/browser/qa/qa-07-cookie-attributes.md","filePath":"domains/browser/qa/qa-07-cookie-attributes.md","lastUpdated":1783504823000}'),d={name:"domains/browser/qa/qa-07-cookie-attributes.md"};function r(c,e,l,s,n,S){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="问答-07-进阶-cookie-属性详解-httponly、secure、samesite-等" tabindex="-1">问答 07（进阶）：Cookie 属性详解：HttpOnly、Secure、SameSite 等 <a class="header-anchor" href="#问答-07-进阶-cookie-属性详解-httponly、secure、samesite-等" aria-label="Permalink to &quot;问答 07（进阶）：Cookie 属性详解：HttpOnly、Secure、SameSite 等&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p><code>Set-Cookie</code> 报头的各个属性（<code>HttpOnly</code>、<code>Secure</code>、<code>SameSite</code>、<code>Domain</code>、<code>Path</code>、<code>Expires</code> / <code>Max-Age</code>）各有什么作用？<code>SameSite</code> 的三个值有什么区别？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>一个完整的 Set-Cookie 例子</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Set-Cookie: sid=abc123; Domain=.example.com; Path=/; Expires=Thu, 01 Jan 2027 00:00:00 GMT; Max-Age=31536000; HttpOnly; Secure; SameSite=Lax</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>属性详解</strong></p><table tabindex="0"><thead><tr><th>属性</th><th>作用</th></tr></thead><tbody><tr><td><code>Domain</code></td><td>允许接收 Cookie 的主机域。缺省时只对当前域生效；写 <code>.example.com</code> 则包含所有子域（如 <code>a.example.com</code>）。</td></tr><tr><td><code>Path</code></td><td>Cookie 只在匹配该 Path 的请求上发送。缺省时为当前 URL 的目录。</td></tr><tr><td><code>Expires</code></td><td>绝对过期时间。</td></tr><tr><td><code>Max-Age</code></td><td>相对过期秒数，<strong>优先级高于 Expires</strong>。都不填则是 Session Cookie，浏览器关闭失效。</td></tr><tr><td><code>HttpOnly</code></td><td>JS 无法通过 <code>document.cookie</code> 读取此 Cookie，防 XSS 窃取。</td></tr><tr><td><code>Secure</code></td><td>仅在 HTTPS 上发送，防中间人截获。</td></tr><tr><td><code>SameSite</code></td><td>控制跨站请求是否携带（防 CSRF）。</td></tr><tr><td><code>Priority</code></td><td>Chrome 私有属性，Low / Medium / High，容量满时决定谁先被驱逐。</td></tr><tr><td><code>Partitioned</code> (CHIPS)</td><td>分区 Cookie：第三方 Cookie 按顶层站点分区，无法跨站追踪。</td></tr><tr><td>名字前缀 <code>__Secure-</code> / <code>__Host-</code></td><td><code>__Secure-</code> 强制 <code>Secure</code>；<code>__Host-</code> 强制 <code>Secure + Path=/ + 无 Domain</code>，用于绑定「精确当前主机」。</td></tr></tbody></table><p><strong>SameSite 三个值</strong></p><ul><li><code>Strict</code>：跨站请求<strong>完全不发送</strong> Cookie。安全性最高，但从外站跳到自站会丢登录态（如从邮件里点链接）。</li><li><code>Lax</code>（Chrome 80+ 默认）：<strong>顶级导航</strong>（GET）会发；<code>POST</code>、<code>iframe</code>、<code>img</code>、<code>XHR</code> 等跨站请求不发。</li><li><code>None</code>：允许跨站发送，但<strong>必须同时带 <code>Secure</code></strong>（HTTPS）。用于第三方登录、跨站 iframe、跨站接口。</li></ul><p><strong>Domain / Path 匹配规则</strong></p><ul><li>Domain 是「后缀」匹配（含子域），Path 是「前缀」匹配。</li><li>例：<code>Domain=.example.com; Path=/api</code> 时，<code>api.example.com/api/x</code> 命中；<code>example.com/user</code> 不命中（Path 不匹配）。</li><li>子域可以设置父域 Cookie，父域不能设子域独享 Cookie。</li></ul><p><strong>Session Cookie vs Persistent Cookie</strong></p><ul><li>无 <code>Expires</code> / <code>Max-Age</code> = Session，浏览器关闭失效（很多现代浏览器会「恢复上次会话」，Session Cookie 也会保留）。</li><li>有具体过期时间 = Persistent，写入磁盘。</li></ul><h2 id="追问-1-httponly-能完全防住-xss-吗-为什么还需要-csp-等其它手段" tabindex="-1">追问 1：<code>HttpOnly</code> 能完全防住 XSS 吗？为什么还需要 CSP 等其它手段？ <a class="header-anchor" href="#追问-1-httponly-能完全防住-xss-吗-为什么还需要-csp-等其它手段" aria-label="Permalink to &quot;追问 1：`HttpOnly` 能完全防住 XSS 吗？为什么还需要 CSP 等其它手段？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>不能。<code>HttpOnly</code> 只防止 <strong>JS 通过 <code>document.cookie</code> 读到 Cookie</strong>，但攻击者仍可能： <ul><li>用 XSS 让浏览器<strong>发起带 Cookie 的请求</strong>（浏览器自动携带），做代理攻击、CSRF、越权操作。</li><li>用 XSS 读取页面里的其他数据（DOM、localStorage、内存中的 Token）。</li><li>通过 CSS injection / DOM 敏感数据抓取。</li></ul></li><li>所以还需要： <ul><li><strong>CSP</strong> 限制脚本源，减少注入落地。</li><li><strong>输出转义 / 框架自动转义</strong> 从源头防注入。</li><li><strong>SameSite Cookie / CSRF Token</strong> 防 CSRF。</li><li><strong>Trusted Types</strong> 强制拒绝危险字符串。</li><li><strong>子资源完整性 SRI</strong>、<code>X-Content-Type-Options</code>、<code>Referrer-Policy</code> 等辅助头。</li></ul></li></ul><h2 id="追问-2-为什么-chrome-从-80-版起把-samesite-默认改为-lax-会带来什么兼容问题" tabindex="-1">追问 2：为什么 Chrome 从 80 版起把 SameSite 默认改为 Lax？会带来什么兼容问题？ <a class="header-anchor" href="#追问-2-为什么-chrome-从-80-版起把-samesite-默认改为-lax-会带来什么兼容问题" aria-label="Permalink to &quot;追问 2：为什么 Chrome 从 80 版起把 SameSite 默认改为 Lax？会带来什么兼容问题？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>目的：<strong>默认防 CSRF</strong>。此前默认是 <code>None</code>（跨站也会发送 Cookie），恶意站点很容易借用户登录态发起请求。</li><li>影响： <ul><li>依赖第三方 Cookie 的场景（第三方登录、iframe 嵌入、跨站单点登录、支付网关）会失效。</li><li>表单跨站 <code>POST</code>（<code>&lt;form action=&quot;https://bank.com/pay&quot;&gt;</code>）不会携带 Cookie。</li></ul></li><li>兼容： <ul><li>明确设 <code>SameSite=None; Secure</code>（必须 HTTPS）。</li><li>若要在 iframe 里保持登录，主域和 iframe 域要么同站，要么设置 <code>SameSite=None; Secure</code>。</li><li>Safari ITP 更激进：跨站第三方 Cookie 直接屏蔽，需要 Storage Access API 请求授权。</li></ul></li><li>未来：Chrome 计划完全废弃第三方 Cookie，改用 CHIPS（<code>Partitioned</code>）+ Privacy Sandbox（FedCM、Topics）。</li></ul><h2 id="追问-3-host-前缀有什么作用-为什么比自己写-secure-path-更安全" tabindex="-1">追问 3：<code>__Host-</code> 前缀有什么作用？为什么比自己写 <code>Secure; Path=/</code> 更安全？ <a class="header-anchor" href="#追问-3-host-前缀有什么作用-为什么比自己写-secure-path-更安全" aria-label="Permalink to &quot;追问 3：`__Host-` 前缀有什么作用？为什么比自己写 `Secure; Path=/` 更安全？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><code>__Host-</code> 前缀强制约束浏览器： <ul><li><strong>必须带 <code>Secure</code></strong>（HTTPS 才写入）。</li><li><strong><code>Path</code> 必须是 <code>/</code></strong>。</li><li><strong>不能设 <code>Domain</code> 属性</strong>，即只属于当前精确主机，不能被子域读到。</li></ul></li><li>这样即使子域被攻陷或存在 XSS，也不能覆写主域的这个 Cookie（防 Cookie Tossing / Fixation）。</li><li><code>__Secure-</code> 前缀只要求 <code>Secure</code>，宽松一些。</li><li>自己写 <code>Secure; Path=/</code> 只是当前站点做出承诺，但恶意子域仍可以创建同名 <code>Domain=.example.com</code> 的 Cookie 覆盖它；<code>__Host-</code> 从协议层堵住了这个洞。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://www.rfc-editor.org/rfc/rfc6265" target="_blank" rel="noreferrer">RFC 6265: HTTP State Management</a>：Cookie 属性与作用域规范</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Reference/Headers/Set-Cookie" target="_blank" rel="noreferrer">MDN: Set-Cookie</a>：HttpOnly / Secure / SameSite 详解</li><li><a href="https://web.dev/articles/samesite-cookies-explained" target="_blank" rel="noreferrer">web.dev: SameSite cookies explained</a>：SameSite 策略与 CSRF 防护</li></ul>',26)])])}const u=o(d,[["render",r]]);export{m as __pageData,u as default};
